        min: Optional['types.DrawingAttemptMinAggregateInput'] = None,
        max: Optional['types.DrawingAttemptMaxAggregateInput'] = None,
        having: Optional['types.DrawingAttemptScalarWhereWithAggregatesInput'] = None,
        count: Optional[Union[bool, 'types.DrawingAttemptCountAggregateInput']] = None,
        order: Optional[Union[Mapping['types.DrawingAttemptScalarFieldKeys', 'types.SortOrder'], List[Mapping['types.DrawingAttemptScalarFieldKeys', 'types.SortOrder']]]] = None,
